package main

import (
	"fmt"
	"os"
	"sort"
	"strings"

	goGit "github.com/go-git/go-git/v6"
)

func cmdStatus(args []string) int {
	var (
		porcelain    bool
		short        bool
		branch       bool
		showUntracked = "normal" // "all", "normal", "no"
	)

	for _, a := range args {
		switch a {
		case "--porcelain", "--porcelain=v1":
			porcelain = true
		case "-s", "--short":
			short = true
		case "--no-short":
			short = false
		case "-b", "--branch":
			branch = true
		case "--no-branch":
			branch = false
		case "-z":
			// NUL-terminated, ignored for now
		case "-u", "--untracked-files", "--untracked-files=all", "-uall":
			showUntracked = "all"
		case "-uno", "--untracked-files=no":
			showUntracked = "no"
		case "-unormal", "--untracked-files=normal":
			showUntracked = "normal"
		case "--column", "--no-column":
			// accepted, ignored (we don't columnize)
		case "-v":
			// verbose â€” would need diff, ignored for now
		default:
			if strings.HasPrefix(a, "--column=") {
				// accepted, ignored
			}
		}
	}

	// Check status.short and status.branch config options.
	if rcfg, err := readRawConfig(); err == nil && !porcelain {
		for _, s := range rcfg.Sections {
			if !s.IsName("status") {
				continue
			}
			if s.HasOption("short") {
				v := strings.ToLower(s.Option("short"))
				if v == "true" || v == "yes" || v == "on" || v == "1" {
					short = true
				}
			}
			if s.HasOption("branch") {
				v := strings.ToLower(s.Option("branch"))
