func longStagingPrefix(code goGit.StatusCode) string {
	switch code {
	case goGit.Added:
		return "new file:   "
	case goGit.Modified:
		return "modified:   "
	case goGit.Deleted:
		return "deleted:    "
	case goGit.Renamed:
		return "renamed:    "
	case goGit.Copied:
		return "copied:     "
	default:
		return ""
	}
}

