		return "new file:   "
	case goGit.Modified:
		return "modified:   "
	case goGit.Deleted:
		return "deleted:    "
	case goGit.Renamed:
		return "renamed:    "
	case goGit.Copied:
		return "copied:     "
	default:
		return ""
	}
}

// longWorktreePrefix returns the prefix for an unstaged change in long format.
func longWorktreePrefix(code goGit.StatusCode) string {
	switch code {
	case goGit.Modified:
		return "modified:   "
	case goGit.Deleted:
		return "deleted:    "
	default:
		return ""
	}
}

