191â†’// countAheadBehind returns (ahead, behind) commit counts between HEAD and
192â†’// the upstream tracking ref.
193â†’func countAheadBehind(repo *goGit.Repository, headHash plumbing.Hash, trackingRefName string) (int, int) {
194â†’	trackingRef, err := repo.Storer.Reference(plumbing.ReferenceName(trackingRefName))
195â†’	if err != nil {
196â†’		return 0, 0
197â†’	}
198â†’	upstreamHash := trackingRef.Hash()
199â†’
200â†’	if headHash == upstreamHash {
201â†’		return 0, 0
202â†’	}
203â†’
204â†’	// Collect commits reachable from HEAD.
205â†’	headSet := make(map[plumbing.Hash]bool)
206â†’	iter, err := repo.Log(&goGit.LogOptions{From: headHash})
207â†’	if err == nil {
208â†’		iter.ForEach(func(c *object.Commit) error {
209â†’			headSet[c.Hash] = true
210â†’			return nil
211â†’		})
212â†’	}
213â†’
214â†’	// Collect commits reachable from upstream.
215â†’	upstreamSet := make(map[plumbing.Hash]bool)
216â†’	iter, err = repo.Log(&goGit.LogOptions{From: upstreamHash})
217â†’	if err == nil {
218â†’		iter.ForEach(func(c *object.Commit) error {
219â†’			upstreamSet[c.Hash] = true
220â†’			return nil
221â†’		})
222â†’	}
223â†’
224â†’	ahead := 0
225â†’	for h := range headSet {
226â†’		if !upstreamSet[h] {
227â†’			ahead++
228â†’		}
229â†’	}
230â†’	behind := 0
231â†’	for h := range upstreamSet {
232â†’		if !headSet[h] {
233â†’			behind++
234â†’		}
235â†’	}
236â†’	return ahead, behind
237â†’}
