475â†’// collapseUntracked returns the untracked entries to display, collapsing
476â†’// directories in "normal" mode. In "all" mode, individual files are shown.
477â†’// In "normal" mode, if a directory contains only untracked files (no tracked
478â†’// files share the directory prefix), the directory name is shown instead.
479â†’func collapseUntracked(untrackedSet map[string]bool, status goGit.Status, mode string) []string {
480â†’	if mode == "no" {
481â†’		return nil
