55â†’
56â†’// fatal prints a fatal error message to stderr and exits with code 128.
57â†’// Note: os.Exit skips deferred calls. This is acceptable for a CLI where
58â†’// defers are only closing file handles (reclaimed by the OS anyway).
59â†’// Do not add deferred writes (lockfiles, flush) that depend on running.
60â†’func fatal(format string, args ...any) {
61â†’	fmt.Fprintf(os.Stderr, "fatal: "+format+"\n", args...)
62â†’	os.Exit(128)
63â†’}
64â†’
65â†’// gitDir returns the .git directory path for the current working directory.
66â†’// In a bare repository (no .git subdirectory, but HEAD exists), returns ".".
67â†’// Note: this duplicates the walk in openRepo/DetectDotGit, but is needed by
68â†’// cmd_config.go which reads raw config files without opening a full repo.
69â†’func gitDir() string {
70â†’	dir := os.Getenv("GIT_DIR")
71â†’	if dir != "" {
72â†’		return dir
73â†’	}
74â†’	// Walk up to find .git
75â†’	wd, err := os.Getwd()
76â†’	if err != nil {
77â†’		return ".git"
78â†’	}
79â†’	for {
80â†’		candidate := filepath.Join(wd, ".git")
81â†’		if fi, err := os.Stat(candidate); err == nil && fi.IsDir() {
82â†’			return candidate
83â†’		}
84â†’		// Check for bare repo (HEAD file exists in current dir).
85â†’		if _, err := os.Stat(filepath.Join(wd, "HEAD")); err == nil {
86â†’			if _, err := os.Stat(filepath.Join(wd, "refs")); err == nil {
87â†’				return wd
88â†’			}
89â†’		}
90â†’		parent := filepath.Dir(wd)
91â†’		if parent == wd {
92â†’			break
93â†’		}
94â†’		wd = parent
95â†’	}
96â†’	return ".git"
97â†’}
