 26â†’	if c.From == empty && c.To == empty {
 27â†’		return merkletrie.Action(0),
 28â†’			fmt.Errorf("malformed change: empty from and to")
 29â†’	}
 30â†’
 31â†’	if c.From == empty {
 32â†’		return merkletrie.Insert, nil
