// indexTree builds a tree from the current index. This is an approximation:
// we use HEAD tree for now (staged changes are HEAD + index delta).
func indexTree(repo *goGit.Repository) *object.Tree {
	// For --cached, we want to show what's staged.
	// go-git's worktree status gives us this info, but Tree.Diff needs Tree objects.
	// As an approximation, we write the index to a tree and resolve it.
	wt, err := repo.Worktree()
	if err != nil {
		return nil
	}
	// WriteTree writes the current index as a tree object.
	hash, err := wt.WriteTree()
	if err != nil {
		return nil
	}
	tree, err := repo.TreeObject(hash)
	if err != nil {
		return nil
	}
	return tree
}

