package main

import (
	"fmt"
	"os"
	"strings"

	"github.com/go-git/go-git/v6"
	"github.com/go-git/go-git/v6/plumbing"
)

func cmdCheckout(args []string) int {
	var (
		create bool
		force  bool
		orphan bool
		branch string
	)

	positional := []string{}
	i := 0
	for i < len(args) {
		a := args[i]
		switch a {
		case "-b":
			create = true
			if i+1 < len(args) {
				i++
				branch = args[i]
			}
		case "-B":
			create = true
			force = true
			if i+1 < len(args) {
				i++
				branch = args[i]
			}
		case "--orphan":
			orphan = true
			if i+1 < len(args) {
				i++
				branch = args[i]
			}
		case "-f", "--force":
			force = true
		case "--detach":
			// Accepted â€” hash checkouts already detach HEAD.
		case "-q", "--quiet":
			// accepted, ignored
		case "-l":
			// accepted, ignored (create reflog â€” we always do)
		case "--":
			// remaining args are paths, stop flag parsing
			i++
			for i < len(args) {
				positional = append(positional, args[i])
				i++
			}
		default:
			if !strings.HasPrefix(a, "-") {
				positional = append(positional, a)
			}
		}
		i++
	}

	repo := openRepoOrDie()

	// --orphan: create a new branch with no history.
	if orphan && branch != "" {
		ref := plumbing.NewSymbolicReference(plumbing.HEAD, plumbing.NewBranchReferenceName(branch))
		if err := repo.Storer.SetReference(ref); err != nil {
			fmt.Fprintf(os.Stderr, "fatal: %s\n", err)
			return 128
		}
		return 0
	}

	wt, err := repo.Worktree()
	if err != nil {
		fmt.Fprintf(os.Stderr, "fatal: %s\n", err)
		return 128
	}

	if create && branch != "" {
		// Handle unborn HEAD (no commits yet): just update the symbolic ref.
		_, headErr := repo.Head()
		if headErr != nil && len(positional) == 0 {
			ref := plumbing.NewSymbolicReference(plumbing.HEAD, plumbing.NewBranchReferenceName(branch))
			if err := repo.Storer.SetReference(ref); err != nil {
				fmt.Fprintf(os.Stderr, "fatal: %s\n", err)
				return 128
			}
			return 0
		}

		opts := &git.CheckoutOptions{
			Branch: plumbing.NewBranchReferenceName(branch),
			Create: true,
			Force:  force,
		}
		// If a start-point was given (e.g., checkout -b topic HEAD~1), resolve it.
		if len(positional) > 0 {
			h, err := repo.ResolveRevision(plumbing.Revision(positional[0]))
			if err != nil {
				fmt.Fprintf(os.Stderr, "fatal: not a valid object name: '%s'\n", positional[0])
				return 128
			}
			opts.Hash = *h
		}
		if err := wt.Checkout(opts); err != nil {
			fmt.Fprintf(os.Stderr, "fatal: %s\n", err)
			return 128
		}
		return 0
	}

	if len(positional) == 0 {
		return 0
	}

	target := positional[0]

	// Try as branch name first.
	branchRef := plumbing.NewBranchReferenceName(target)
	if _, err := repo.Storer.Reference(branchRef); err == nil {
		opts := &git.CheckoutOptions{
			Branch: branchRef,
			Force:  force,
		}
		if err := wt.Checkout(opts); err != nil {
			fmt.Fprintf(os.Stderr, "fatal: %s\n", err)
			return 128
		}
		return 0
	}

	// Try as tag.
	tagRef := plumbing.NewTagReferenceName(target)
	if _, err := repo.Storer.Reference(tagRef); err == nil {
		opts := &git.CheckoutOptions{
			Branch: tagRef,
			Force:  force,
		}
		if err := wt.Checkout(opts); err != nil {
			fmt.Fprintf(os.Stderr, "fatal: %s\n", err)
			return 128
		}
		return 0
	}

	// Try as hash (detached HEAD).
	hash, err := repo.ResolveRevision(plumbing.Revision(target))
	if err != nil {
		fmt.Fprintf(os.Stderr, "error: pathspec '%s' did not match any file(s) known to git\n", target)
		return 1
	}

	opts := &git.CheckoutOptions{
		Hash:  *hash,
		Force: force,
	}
	if err := wt.Checkout(opts); err != nil {
		fmt.Fprintf(os.Stderr, "fatal: %s\n", err)
		return 128
	}

	return 0
}

package main

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"
)

// command is a subcommand handler. It receives the remaining args after the
// subcommand name and returns an exit code.
type command func(args []string) int

var commands map[string]command

// allCommands returns the list of known subcommand names (for install symlinks).
func allCommands() []string {
	names := make([]string, 0, len(commands))
	for name := range commands {
		names = append(names, name)
	}
	return names
}

func init() {
	commands = map[string]command{
		"version":      cmdVersion,
		"init":         cmdInit,
		"config":       cmdConfig,
		"install":      cmdInstall,
		"hash-object":  cmdHashObject,
		"update-ref":   cmdUpdateRef,
		"symbolic-ref": cmdSymbolicRef,
		"show-ref":     cmdShowRef,
		"rev-parse":    cmdRevParse,
		"cat-file":     cmdCatFile,
		"ls-tree":      cmdLsTree,
		"add":          cmdAdd,
		"commit":       cmdCommit,
		"status":       cmdStatus,
		"branch":       cmdBranch,
		"tag":          cmdTag,
		"log":          cmdLog,
		"checkout":     cmdCheckout,
		"remote":       cmdRemote,
		"push":         cmdPush,
		"fetch":        cmdFetch,
		"show":          cmdShow,
		"read-tree":     cmdReadTree,
		"pack-refs":     cmdPackRefs,
		"diff":          cmdDiff,
		"diff-files":    cmdDiffFiles,
		"diff-index":    cmdDiffIndex,
		"merge":         cmdUnimplemented,
		"reset":         cmdReset,
		"rm":            cmdRm,
		"mv":            cmdMv,
		"clone":         cmdClone,
		"update-index":  cmdUpdateIndex,
		"reflog":        cmdReflog,
		"worktree":      cmdWorktree,
		"write-tree":    cmdWriteTree,
		"commit-tree":   cmdCommitTree,
		"ls-files":      cmdLsFiles,
		"switch":        cmdSwitch,
		"for-each-ref":  cmdForEachRef,
		"pull":          cmdUnimplemented,
	}
}

func main() {
	// Multicall: if invoked as "git-foo", treat "foo" as the subcommand.
	base := filepath.Base(os.Args[0])
	if strings.HasPrefix(base, "git-") {
		subcmd := strings.TrimPrefix(base, "git-")
		os.Exit(dispatch(subcmd, os.Args[1:]))
	}

	// Normal: "git [global-flags] <command> [args...]"
	globals, subcmd, args := parseGlobalFlags(os.Args[1:])

	if globals.showVersion {
		os.Exit(cmdVersion(nil))
	}
	if globals.showExecPath {
		fmt.Println(execPath())
		os.Exit(0)
	}

	if subcmd == "" {
		fmt.Fprintln(os.Stderr, "usage: git [--version] [--exec-path] [-C <path>] [-c <key>=<value>] <command> [<args>]")
		os.Exit(1)
	}

	applyGlobals(globals)
	// Prepend any forwarded global flags to the subcommand args.
	if len(globals.forwardArgs) > 0 {
		args = append(globals.forwardArgs, args...)
	}
	os.Exit(dispatch(subcmd, args))
}

func dispatch(name string, args []string) int {
	fn, ok := commands[name]
	if !ok {
		logUnimplemented(name)
		fmt.Fprintf(os.Stderr, "git: '%s' is not a git command. See 'git --help'.\n", name)
		return 1
	}
	return fn(args)
}

func logUnimplemented(cmd string) {
	logPath := os.Getenv("GIT_TEST_UNIMPLEMENTED_LOG")
	if logPath == "" {
		return
	}
	f, err := os.OpenFile(logPath, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644)
	if err != nil {
		return
	}
	defer f.Close()
	fmt.Fprintf(f, "%s\n", cmd)
}

func cmdUnimplemented(args []string) int {
	// Recover the command name from argv[0] or args.
	cmd := "unknown"
	base := filepath.Base(os.Args[0])
	if strings.HasPrefix(base, "git-") {
		cmd = strings.TrimPrefix(base, "git-")
	} else if len(os.Args) > 1 {
		cmd = os.Args[1]
	}
	logUnimplemented(cmd)
	fmt.Fprintf(os.Stderr, "fatal: command not yet implemented in go-git\n")
	return 128
}

