148	// buildSignature creates a Signature from env vars or --author string.
149	func buildSignature(authorStr, role string) *object.Signature {
150		name := os.Getenv("GIT_" + role + "_NAME")
151		email := os.Getenv("GIT_" + role + "_EMAIL")
152		dateStr := os.Getenv("GIT_" + role + "_DATE")
153	
154		if authorStr != "" && role == "AUTHOR" {
155			// Parse "Name <email>" format.
156			if idx := strings.Index(authorStr, " <"); idx >= 0 {
157				name = authorStr[:idx]
158				rest := authorStr[idx+2:]
159				if end := strings.Index(rest, ">"); end >= 0 {
160					email = rest[:end]
161				}
162			}
163		}
164	
165		if name == "" || email == "" {
166			return nil // let go-git read from config
167		}
168	
169		when := time.Now()
170		if dateStr != "" {
171			// Try unix timestamp format: "1234567890 +0000"
172			if parsed, err := parseGitDate(dateStr); err == nil {
173				when = parsed
174			}
175		}
176	
177		return &object.Signature{
178			Name:  name,
179			Email: email,
180			When:  when,
181		}
182	}
183	
184	func parseGitDate(s string) (time.Time, error) {
185		// Try "@<unix> <tz>" format (used by test framework).
186		if strings.HasPrefix(s, "@") {
187			s = s[1:]
188		}
189		// Try "unix tz" format.
190		parts := strings.Fields(s)
191		if len(parts) >= 1 {
192			var unix int64
193			if _, err := fmt.Sscanf(parts[0], "%d", &unix); err == nil {
194				t := time.Unix(unix, 0)
195				if len(parts) >= 2 {
196					loc, err := time.Parse("-0700", parts[1])
197					if err == nil {
198						t = t.In(loc.Location())
199					}
200				}
201				return t, nil
202			}
203		}
204		// Try RFC2822-ish.
205		for _, layout := range []string{
206			time.RFC1123Z,
207			time.RFC3339,
208			"Mon, 2 Jan 2006 15:04:05 -0700",
209		} {
210			if t, err := time.Parse(layout, s); err == nil {
211				return t, nil
212			}
213		}
214		return time.Time{}, fmt.Errorf("cannot parse date: %s", s)
215	}
