58				} else if !strings.HasPrefix(a, "-") {
59					positional = append(positional, a)
60				}
61			}
62			i++
63		}
64	
65		if len(positional) >= 1 {
66			remoteName = positional[0]
67			refSpecs = positional[1:]
68		}
69		if remoteName == "" && !all {
70			remoteName = "origin"
71		}
72	
73		repo := openRepoOrDie()
74	
75		if all {
76			remotes, err := repo.Remotes()
77			if err != nil {
78				fmt.Fprintf(os.Stderr, "fatal: %s\n", err)
79				return 128
80			}
81			for _, r := range remotes {
82				opts := &git.FetchOptions{
83					RemoteName: r.Config().Name,
84					Force:      force,
85					Prune:      prune,
86				}
87				setFetchTags(opts, tags, noTags)
88				err := repo.Fetch(opts)
89				if err != nil && !isTagExistsOrUpToDate(err) {
90					fmt.Fprintf(os.Stderr, "fatal: %s\n", err)
91					return 128
92				}
93			}
94			return 0
95		}
96	
97		// Check if remoteName is a configured remote or a URL/path.
98		isURL := false
99		if remoteName != "" {
100			if _, err := repo.Remote(remoteName); err != nil {
101				// Not a named remote â€” treat as URL/path.
102				isURL = true
103			}
104		}
105	
106		if isURL {
107			// Resolve local paths to absolute.
108			url := remoteName
109			if !strings.Contains(url, "://") && !strings.HasPrefix(url, "git@") {
110				if abs, err := filepath.Abs(url); err == nil {
111					url = abs
112				}
113			}
114	
115			// Build refspecs for direct URL fetch.
116			var rs []config.RefSpec
117			for _, r := range refSpecs {
118				rs = append(rs, config.RefSpec(r))
119			}
120			if len(rs) == 0 {
121				// Default: fetch all heads + tags.
122				rs = append(rs, config.RefSpec("+refs/heads/*:refs/heads/*"))
123				rs = append(rs, config.RefSpec("+refs/tags/*:refs/tags/*"))
124			}
125	
126			remote, err := repo.CreateRemoteAnonymous(&config.RemoteConfig{
127				Name: "anonymous",
128				URLs: []string{url},
129			})
130			if err != nil {
131				fmt.Fprintf(os.Stderr, "fatal: %s\n", err)
132				return 128
133			}
134	
135			fetchOpts := &git.FetchOptions{
136				RemoteName: "anonymous",
137				RefSpecs:   rs,
138				Force:      force,
139				Depth:      depth,
140			}
141			setFetchTags(fetchOpts, tags, noTags)
142	
143			err = remote.Fetch(fetchOpts)
144			if err != nil && !isTagExistsOrUpToDate(err) {
145				fmt.Fprintf(os.Stderr, "fatal: %s\n", err)
146				return 128
147			}
148			return 0
149		}
150	
151		opts := &git.FetchOptions{
152			RemoteName: remoteName,
153			Force:      force,
154			Prune:      prune,
155			Depth:      depth,
156		}
157		setFetchTags(opts, tags, noTags)
158	
159		if len(refSpecs) > 0 {
160			for _, rs := range refSpecs {
161				if !strings.Contains(rs, ":") && !strings.HasPrefix(rs, "refs/") {
162					rs = fmt.Sprintf("refs/heads/%s:refs/remotes/%s/%s", rs, remoteName, rs)
163				}
164				opts.RefSpecs = append(opts.RefSpecs, config.RefSpec(rs))
165			}
166		}
167	
168		err := repo.Fetch(opts)
169		if err != nil && !isTagExistsOrUpToDate(err) {
170			fmt.Fprintf(os.Stderr, "fatal: %s\n", err)
171			return 128
172		}
173	
174		return 0
175	}
176	
177	func setFetchTags(opts *git.FetchOptions, tags, noTags bool) {
178		if noTags {
179			opts.Tags = plumbing.NoTags
180		} else if tags {
181			opts.Tags = plumbing.AllTags
182		}
183	}
184	
185	// isTagExistsOrUpToDate returns true if the error is a benign fetch result:
186	// either already up-to-date or a tag that already exists (go-git bug â€” real
187	// git silently skips existing tags during fetch).
188	func isTagExistsOrUpToDate(err error) bool {
189		if err == nil {
190			return true
191		}
192		if errors.Is(err, git.NoErrAlreadyUpToDate) {
193			return true
194		}
195		if errors.Is(err, git.ErrTagExists) {
196			return true
197		}
198		// Fallback: string match in case the error is wrapped without %w.
199		return strings.Contains(err.Error(), "tag already exists")
200	}
