					fmt.Fprintf(os.Stderr, "error in tree %s: %s\n", h, err)
				}
				*exitCode = 1
				continue
			}
			for _, entry := range tree.Entries {
				stack = append(stack, entry.Hash)
			}

		case plumbing.TagObject:
			tag, err := object.DecodeTag(repo.Storer, obj)
